class Node:
    def __init__(self, value):
        self.value = value
        self.left = None
        self.right = None

def insert(root, char):
    if root is None:
        return Node(char)
    if char < root.value:
        root.left = insert(root.left, char)
    elif char > root.value:
        root.right = insert(root.right, char)
    return root

def process_sequence(sequence, index=0, tree=None, seen=None):
    if seen is None:
        seen = set()
    if tree is None:
        tree = None

    if index >= len(sequence):
        return tree

    char = sequence[index].lower()

    if char not in seen:
        seen.add(char)
        tree = insert(tree, char)

    return process_sequence(sequence, index + 1, tree, seen)

# Example usage
